<script setup lang="ts">
import{onMounted,ref}from'vue';import{api}from'@/services/api';import{useCartStore}from'@/stores/cart';const cart=useCartStore();const products=ref<any[]>([]);const search=ref('');async function load(){products.value=(await api<any>(`/api/public/store/products?size=50&search=${encodeURIComponent(search.value)}`)).content}async function add(p:any){await cart.add('store',p.id);alert(`${p.name} agregado al carrito`)}const money=(v:number,c='USD')=>new Intl.NumberFormat('es-HN',{style:'currency',currency:c}).format(v);onMounted(load);
</script>

<template>
<main class="storefront"><section class="store-hero"><div><span class="eyebrow">TIENDA TRASTCMS</span><h1>Productos, servicios y recursos para construir mejor</h1><p>Una tienda demostrativa conectada al catálogo, inventario, carrito y checkout de TrastPay.</p><form class="store-search" @submit.prevent="load"><input v-model="search" placeholder="Buscar productos, temas o servicios"><button>Buscar</button></form></div><div class="store-hero-card"><span>{{cart.count}}</span><b>artículos en su carrito</b><RouterLink to="/cart" class="button">Ver carrito</RouterLink></div></section><section class="content-section"><div class="section-heading"><div><span class="eyebrow">CATÁLOGO</span><h2>Explorar productos</h2></div></div><div class="store-grid"><article v-for="p in products" :key="p.id" class="product-card"><div class="product-media" :style="p.featuredImageUrl?{backgroundImage:`url(${p.featuredImageUrl})`}:{}"><span v-if="p.featured" class="status-pill ok">Destacado</span></div><div class="p-5"><small>{{p.category||p.type}}</small><h3>{{p.name}}</h3><p>{{p.shortDescription}}</p><div class="mt-5 flex items-center justify-between"><strong>{{money(p.price,p.currency)}}</strong><button class="button small" :disabled="!p.inStock" @click="add(p)">{{p.inStock?'Agregar':'Agotado'}}</button></div></div></article></div></section></main></template>
